mapper.select:
SELECT total_usage_data
FROM DAILY_TOTAL_DATA
WHERE line_id = #{lineId}
  AND usage_date = #{usageDate}
  AND deleted_at IS NULL

SELECT total_usage_data
FROM DAILY_APP_TOTAL_DATA
WHERE line_id = #{lineId}
  AND application_id = #{appId}
  AND usage_date = #{usageDate}
  AND deleted_at IS NULL

SELECT COALESCE(SUM(usage_amount), 0)
FROM FAMILY_SHARED_USAGE_DAILY
WHERE line_id = #{lineId}
  AND usage_date >= #{monthStart}
  AND usage_date < #{nextMonthStart}
  AND deleted_at IS NULL
